import { fail, redirect } from '@sveltejs/kit';
import type { Actions } from './$types';
import postgres from 'postgres';
import { compare as bcryptCompare } from '@node-rs/bcrypt';
import { verify, hash } from '@node-rs/argon2';

const sql = postgres();

export const actions: Actions = {
    default: async ({ request, cookies }) => {
        const data = await request.formData();
        const username = data.get('username') as string;
        const password = data.get('password') as string;

        if (!username || !password) {
            return fail(400, { error: 'Username and password are required' });
        }

        const [user] = await sql`
            SELECT id, pw_hash, pw_attempts FROM users
            WHERE username = ${username} OR email = ${username}
        `;

        const isBcrypt = user.pw_hash.startsWith('$2y$') || user.pw_hash.startsWith('$2b$');

        // Node's bcrypt doesn't recognize the php shit $2y$, replace with $2b$
        const hashForCompare = user.pw_hash.replace(/^\$2y\$/, '$2b$');

        const valid = isBcrypt
            ? await bcryptCompare(password, hashForCompare)
            : await verify(user.pw_hash, password);

        if (!valid) {
            await sql`
                UPDATE users SET pw_attempts = pw_attempts + 1 WHERE id = ${user.id}
            `;
            return fail(401, { error: 'Invalid username or password' });
        }

        // Migrate bcrypt → argon2 on successful login
        if (isBcrypt) {
            const newHash = await hash(password);
            await sql`
                UPDATE users SET pw_hash = ${newHash}, pw_attempts = 0 WHERE id = ${user.id}
            `;
        } else {
            await sql`UPDATE users SET pw_attempts = 0 WHERE id = ${user.id}`;
        }

        // Create session
        const [session] = await sql`
            INSERT INTO sessions (player_id, token, expires_at)
            VALUES (${user.id}, gen_random_uuid(), now() + interval '30 days')
            RETURNING token
        `;

        cookies.set('session', session.token, {
            httpOnly: true,
            secure: true,
            sameSite: 'strict',
            maxAge: 60 * 60 * 24 * 30,
            path: '/'
        });

        redirect(303, '/');
    }
};

import { fail, redirect } from '@sveltejs/kit';
import type { Actions } from './$types';

export const actions: Actions = {
    default: async ({ request, locals }) => {
        if (!locals.user) return fail(401, { error: 'Not logged in' });

        const data = await request.formData();
        const entry = data.get('save');
        if (!(entry instanceof File) || entry.size === 0) {
            return fail(400, { error: 'No file selected' });
        }
        const file = entry;

        const name = file.name.toLowerCase();
        if (!name.endsWith('.civ6save')) {
            return fail(400, { error: `Invalid file extension: ${file.name}` });
        }

        let res: Response;
        try {
            res = await fetch('http://localhost:8080/parse', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/octet-stream',
                    'X-Filename': file.name,
                },
                body: await file.arrayBuffer(),
            });
        } catch {
            return fail(502, { error: 'Parser service unavailable' });
        }

        if (!res.ok) {
            const errText = await res.text();
            return fail(500, { error: `Failed to parse save file: ${errText}` });
        }

        const { game_id } = await res.json();
        redirect(303, `/matches/confirm/${game_id}`);
    }
};

import type { LayoutServerLoad } from './$types';

export const load: LayoutServerLoad = async ({ locals }) => {
    return { user: locals.user ?? null };
};

import postgres from 'postgres';
import type { Handle } from '@sveltejs/kit';

const sql = postgres();

export const handle: Handle = async ({ event, resolve }) => {
    const token = event.cookies.get('session');

    if (token) {
        const [session] = await sql`
            SELECT s.player_id, u.username, u.privileges, p.name
            FROM sessions s
            JOIN users u ON u.id = s.player_id
            LEFT JOIN players p ON p.id = s.player_id
            WHERE s.token = ${token}
            AND s.expires_at > now()
        `;
        if (session) {
            event.locals.user = {
                id: session.player_id,
                username: session.username,
                name: session.name,
                privileges: session.privileges,
            };
        }
    }

    return resolve(event);
};

